    input_path = uploaded.tempfile.path
    output_basename = "converted_#{SecureRandom.hex(8)}"
    output_dir = Rails.root.join("tmp", "processed_images")
    FileUtils.mkdir_p(output_dir)
    output_path = output_dir.join("#{output_basename}.#{format}")

    command = [
      "convert",
      input_path.to_s,
      "-resize",
      size,
      output_path.to_s
    ]

    success = system(*command)

    unless success && File.exist?(output_path)
      render json: { error: "Image conversion failed" }, status: :unprocessable_entity
      return
    end

    send_file output_path, type: Marcel::MimeType.for(Pathname.new(output_path.to_s)), disposition: "attachment"
  ensure
    File.delete(output_path) if defined?(output_path) && output_path && File.exist?(output_path)
  end

