  def ensure_image_param!
    return if params[:image].respond_to?(:tempfile)

    render json: { error: "Image file is required" }, status: :bad_request
  end

  def normalize_format(value)
    format = value.to_s.downcase.strip
    ALLOWED_FORMATS.include?(format) ? format : nil
  end

